mapper.select:
select id, monogram, email, version
from portfolio.site_profile
where id = #{siteId}

choose.when:
select locale, display_name, secondary_name
from portfolio.site_profile_translation where site_id=#{siteId}
order by locale

select locale, title, description
from portfolio.site_seo_translation where site_id=#{siteId}
order by locale

select id, target, sort_order, visible
from portfolio.site_navigation_item where site_id=#{siteId}
order by sort_order, id

select locale, label, title, statement, focus_label, focus_title, focus_intro
from portfolio.about_section_translation where site_id=#{siteId}
order by locale

select locale, title, body_markdown
from portfolio.privacy_notice_translation where site_id=#{siteId}
order by locale

select id, platform, url, sort_order, visible
from portfolio.social_link where site_id=#{siteId}
order by sort_order, id

select id, external_key, sort_order
from portfolio.profile_fact where site_id=#{siteId}
order by sort_order, id

select id, external_key, sort_order
from portfolio.profile_skill where site_id=#{siteId}
order by sort_order, id

select locale, label, title, introduction
from portfolio.roadmap_header_translation where site_id=#{siteId}
order by locale

select id, external_key, number_label, sort_order, visible
from portfolio.roadmap_stage where site_id=#{siteId}
order by sort_order, id

select id, locale, media_asset_id, version_label, is_current, document_date
from portfolio.resume_document where site_id=#{siteId}
order by locale, document_date desc, id

mapper.update:
update portfolio.site_profile
set monogram=#{monogram}, email=#{email}, version=version+1, updated_at=#{updatedAt}
where id=#{siteId} and version=#{expectedVersion}
